function gResolve(metric){
  var g=GRAPHS[metric];
  var cur=(typeof viewState!=='undefined'&&viewState[metric])||g.def;
  var view=null; for(var i=0;i<g.views.length;i++){ if(g.views[i].id===cur){view=g.views[i];break;} }
  if(!view){ view=g.views[0]; cur=view.id; }
  var det=(typeof detailState!=='undefined')&&!!detailState[metric];
  return {g:g,cur:cur,view:view,det:det};
}
/* CLIENT view: clean chart only, no controls. Coach clicks it to edit. */
function clientGraph(metric){
  var r=gResolve(metric);
  var seld=(typeof selectedMetric!=='undefined'&&selectedMetric===metric)?' sel':'';
  return '<div class="mc blk graph'+seld+'" data-id="g_'+metric+'" data-select="'+metric+'"><div class="ghead2"><div class="lbl">'+r.g.name+'</div></div><div class="gbody2">'+r.view.render(r.det)+'</div></div>';
}
/* COACH side editor: pick chart style + detail, or ask Milton. Never shown to clients. */
function graphEditorHTML(metric){
  var r=gResolve(metric);
  var chips=r.g.views.map(function(v){ return '<span class="gchip'+(v.id===r.cur?' sel':'')+'" data-gv="'+metric+':'+v.id+'">'+v.name+'</span>'; }).join('');
  var dtoggle='<div class="gseg"><span class="'+(!r.det?'sel':'')+'" data-gx="'+metric+':0">Compact</span><span class="'+(r.det?'sel':'')+'" data-gx="'+metric+':1">Detailed</span></div>';
  var hint=(r.cur!==r.g.def)?'<div class="ghint"><span class="mk">M</span>Saved as the default '+r.view.name.toLowerCase()+' view for '+r.g.name.toLowerCase()+'.</div>':'';
  var sugg='<div class="gsugg"><div class="sl"><span class="mk">M</span>Ask Milton</div>'+r.g.sugg.map(function(s){return '<button class="gs" data-gs="'+metric+'::'+s.a+'">'+s.l+'</button>';}).join('')+'</div>';
  return '<div class="ged-h"><div><span class="ged-eyebrow">Editing</span><div class="ged-name">'+r.g.name+'</div></div><span class="ged-tag">Coach only</span></div>'
    +'<div class="ged-label">Chart style</div><div class="gviews">'+chips+'</div>'
    +'<div class="ged-label">Level of detail</div>'+dtoggle
    +hint+sugg
    +'<div class="ged-foot">This is exactly what your client sees. They can\\u2019t change it.</div>';
}

