  /* header pieces handled in assembly; program context here */
  program_context:function(){ return card('program_context','<div class="lbl">Program</div><div class="h-strong" style="margin:6px 0 10px;">12-Week Strength Build · Phase 2</div><div class="bar"><i style="width:25%"></i></div><div class="sub">Week 3 of 12</div>'); },

  focus_week:function(){
    if(ctx.darkFocus){
      return card('focus_week','<div class="lbl" style="color:#5cdb95;">This week\\u2019s focus</div><div style="font-size:16px;font-weight:600;line-height:1.35;margin-top:9px;">'+ctx.focusText+'</div>'+(on.has('coach_badge')?'<div style="margin-top:13px;"><span class="pill" style="background:rgba(92,219,149,.16);color:#5cdb95;">'+RINGCHK+'Coach approved</span></div>':''),'dark');
    }
    return card('focus_week','<div class="barrow" style="margin-bottom:14px;"><div class="h-strong" style="font-size:15px;">This week\\u2019s focus</div>'+(on.has('coach_badge')?'<span class="pill ok">'+RINGCHK+'Approved</span>':'')+'</div><div class="row" style="align-items:flex-start;"><div class="goalicon" style="background:'+ctx.iconSoft+';">'+ICON[ctx.focusIcon]+'</div><div style="font-size:15px;font-weight:600;line-height:1.35;">'+ctx.focusText+'</div></div>');
  },
  focus_today:function(){ return card('focus_today','<div class="lbl" style="color:#2b7a78;">Today\\u2019s focus</div><div class="h-strong" style="margin-top:8px;line-height:1.35;">Complete your workout, then text Milton your dinner tonight.</div>'); },
  weekly_summary:function(){ return card('weekly_summary','<div class="lbl">Weekly summary</div><div style="font-size:13.5px;line-height:1.55;margin-top:8px;">Completed <b>3 of 4</b> workouts, logged <b>18 meals</b>, protein hit <b>5 of 7</b> days.</div>'); },
  coach_note:function(){ return card('coach_note','<div class="lbl" style="color:'+ctx.eyeColor+';">Coach note</div><div style="font-size:13.5px;line-height:1.6;color:#26403a;margin:8px 0 12px;">'+ctx.note+'</div><div class="row"><div class="av" style="background:'+ctx.avGrad+';">'+ctx.initial+'</div><div class="h-strong">'+ctx.coachName+'</div></div>'); },
  milton_takeaway:function(){ return card('milton_takeaway','<div class="row" style="margin-bottom:8px;"><div class="mark">M</div><div class="lbl" style="color:#2b7a78;">Milton takeaway</div></div><div style="font-size:13px;line-height:1.55;color:#173a2f;">'+ctx.noticed+'</div>','tint'); },

  /* A weight & body */
