  v_weight_band:function(){ return card('v_weight_band','<div class="lbl" style="margin-bottom:8px;">Weight, weekly average</div><svg class="spark" viewBox="0 0 240 54" preserveAspectRatio="none"><path d="M6,16 L44,28 L82,18 L120,32 L158,24 L196,36 L234,28 L234,42 L196,48 L158,36 L120,44 L82,30 L44,40 L6,28 Z" fill="rgba(58,175,169,.12)"/><polyline points="6,22 44,34 82,24 120,38 158,30 196,42 234,28" fill="none" stroke="#3aafa9" stroke-width="2.4" stroke-linecap="round"/></svg>'+axis('Daily range','— weekly avg')); },
  v_goal_bar:function(){ return card('v_goal_bar','<div class="barrow"><div class="h-strong">5.2 lb lost</div><span class="lbl">of 15 lb goal</span></div><div class="bar"><i style="width:35%"></i></div><div class="sub">19 of 28 days tracked</div>'); },
  v_measure_trend:function(){ return card('v_measure_trend','<div class="lbl" style="margin-bottom:10px;">Measurements (in)</div><div class="stk" style="gap:10px;"><div><div class="barrow" style="margin-bottom:4px;"><span class="sub" style="margin:0;">Waist</span><span class="lbl">34 → 32.5</span></div><div class="bar" style="height:7px;"><i style="width:62%"></i></div></div><div><div class="barrow" style="margin-bottom:4px;"><span class="sub" style="margin:0;">Hips</span><span class="lbl">41 → 40</span></div><div class="bar" style="height:7px;"><i style="width:74%"></i></div></div></div>'); },
  v_measure_cards:function(){ return wrap('v_measure_cards','<div style="display:flex;gap:9px;margin-bottom:11px;"><div class="mc" style="margin:0;flex:1;text-align:center;"><div class="lbl">Start</div><div class="val" style="font-size:19px;margin-top:6px;">34.0</div></div><div class="mc" style="margin:0;flex:1;text-align:center;"><div class="lbl">Now</div><div class="val" style="font-size:19px;margin-top:6px;">32.5</div></div><div class="mc tint" style="margin:0;flex:1;text-align:center;"><div class="lbl" style="color:#2b7a78;">Change</div><div class="val up" style="font-size:19px;margin-top:6px;">-1.5</div></div></div>'); },
  v_photo_compare:function(){ return wrap('v_photo_compare','<div style="display:flex;gap:9px;margin-bottom:11px;"><div class="ph" style="flex:1;"><div class="blur pa"></div><div class="tag">Start · May 1</div></div><div class="ph" style="flex:1;"><div class="blur pb"></div><div class="tag">Now · May 26</div></div></div>'); },
  v_photo_timeline:function(){ return wrap('v_photo_timeline','<div style="display:flex;gap:7px;margin-bottom:11px;"><div style="flex:1;"><div class="ph sq"><div class="blur pa"></div></div><div class="lbl" style="text-align:center;margin-top:4px;">Apr</div></div><div style="flex:1;"><div class="ph sq"><div class="blur pb"></div></div><div class="lbl" style="text-align:center;margin-top:4px;">May</div></div><div style="flex:1;"><div class="ph sq"><div class="blur pc"></div></div><div class="lbl" style="text-align:center;margin-top:4px;">Jun</div></div></div>'); },
  v_bodycomp_card:function(){ return card('v_bodycomp_card','<div class="lbl">Body composition</div><div style="display:flex;justify-content:space-between;margin-top:10px;"><div><div class="val" style="font-size:21px;">22<span class="u">%</span></div><div class="sub" style="margin-top:3px;">Body fat</div></div><div><div class="val" style="font-size:21px;">128<span class="u">lb</span></div><div class="sub" style="margin-top:3px;">Lean mass</div></div></div>'); },
  v_bodycomp_trend:function(){ return card('v_bodycomp_trend','<div class="lbl" style="margin-bottom:8px;">Fat vs lean mass</div><svg class="spark" viewBox="0 0 240 54" preserveAspectRatio="none"><polyline points="6,38 44,36 82,34 120,30 158,28 196,25 234,22" fill="none" stroke="#3aafa9" stroke-width="2.4" stroke-linecap="round"/><polyline points="6,22 44,24 82,25 120,28 158,31 196,34 234,36" fill="none" stroke="#1a2e2a" stroke-width="2.2" stroke-dasharray="1 5" stroke-linecap="round"/></svg>'+axis('— Lean','··· Fat')); },

  /* B nutrition */
  v_meal_cal:function(){ return card('v_meal_cal','<div class="lbl" style="margin-bottom:9px;">Meals logged</div>'+days([1,1,'p',1,1,0,0])); },
