  v_protein_line:function(){ return card('v_protein_line','<div class="lbl" style="margin-bottom:8px;">Protein vs target</div><svg class="spark" viewBox="0 0 240 50" preserveAspectRatio="none"><line x1="6" y1="16" x2="234" y2="16" stroke="#1a2e2a" stroke-width="1.2" stroke-dasharray="3 4" opacity=".4"/><polyline points="6,22 44,14 82,20 120,12 158,24 196,14 234,16" fill="none" stroke="#3aafa9" stroke-width="2.4" stroke-linecap="round"/></svg>'+axis('Daily','··· target')); },
