  v_macro_dist:function(){ return card('v_macro_dist','<div class="lbl" style="margin-bottom:10px;">Macro split</div><div style="display:flex;align-items:center;gap:16px;"><svg width="64" height="64" viewBox="0 0 36 36" style="transform:rotate(-90deg);"><circle cx="18" cy="18" r="15.5" fill="none" stroke="#e4ebe8" stroke-width="5"/><circle cx="18" cy="18" r="15.5" fill="none" stroke="#3aafa9" stroke-width="5" stroke-dasharray="39 97" stroke-linecap="round"/><circle cx="18" cy="18" r="15.5" fill="none" stroke="#5cdb95" stroke-width="5" stroke-dasharray="34 102" stroke-dashoffset="-39"/><circle cx="18" cy="18" r="15.5" fill="none" stroke="#1a2e2a" stroke-width="5" stroke-dasharray="24 112" stroke-dashoffset="-73"/></svg><div style="font-size:12px;line-height:1.9;"><div><b style="color:#2b7a78">40%</b> Protein</div><div><b style="color:#1f7a3e">35%</b> Carbs</div><div><b>25%</b> Fat</div></div></div>'); },
  v_macro_grid:function(){ var rows=[['Protein',[1,1,2,1,1,0,0]],['Cals',[1,1,1,2,1,1,0]],['Carbs',[2,1,1,1,0,1,1]],['Fat',[1,2,1,1,1,0,1]]]; return card('v_macro_grid','<div class="lbl" style="margin-bottom:9px;">Macro adherence</div><div class="stk" style="gap:5px;">'+rows.map(function(r){return '<div style="display:flex;gap:5px;align-items:center;"><span class="lbl" style="width:42px;">'+r[0]+'</span>'+mbar(r[1])+'</div>';}).join('')+'</div>'); },
  v_quality:function(){ return card('v_quality','<div class="barrow"><span class="lbl">Meal quality</span><span class="val" style="font-size:21px;">82<span class="u">/100</span></span></div><svg class="spark" viewBox="0 0 240 34" preserveAspectRatio="none" style="height:30px;"><polyline points="6,26 50,22 94,24 138,16 182,14 234,10" fill="none" stroke="#3aafa9" stroke-width="2.4" stroke-linecap="round"/></svg>'); },
  v_best_meal:function(){ return card('v_best_meal','<div class="row"><div class="ph" style="width:42px;height:42px;border-radius:9px;"><div class="blur pb"></div></div><div><div class="h-strong" style="font-size:13px;">Best meal · Greek bowl</div><div class="sub" style="margin-top:2px;">42g protein, lean + fiber</div></div></div>'); },
  v_meal_pattern:function(){ return card('v_meal_pattern','<div class="lbl" style="color:#2b7a78;">Pattern</div><div style="font-size:13px;line-height:1.5;margin-top:6px;color:#173a2f;">Breakfast was your most consistent meal. Protein dipped on weekend dinners.</div>','tint'); },
