  v_streak_card:function(){ return card('v_streak_card','<div style="text-align:center;"><div class="val" style="font-size:32px;color:#5cdb95;">6</div><div class="lbl" style="color:#5cdb95;margin-top:4px;">day logging streak</div></div>','dark'); },
