  v_recovery:function(){ return card('v_recovery','<div class="barrow"><span class="lbl">Recovery</span><span class="pill mint">Moderate</span></div><svg class="spark" viewBox="0 0 240 34" preserveAspectRatio="none" style="height:30px;"><polyline points="6,24 50,14 94,20 138,12 182,18 234,10" fill="none" stroke="#3aafa9" stroke-width="2.2" stroke-linecap="round"/></svg>'); },
  v_mood:function(){ var e=['🙂','🙂','😐','😄','🙂','😐','😄']; var bg=['#5cdb95','#5cdb95','#e4ebe8','#3aafa9','#5cdb95','#e4ebe8','#3aafa9']; var h=''; for(var i=0;i<7;i++){ h+='<div class="day"><div class="dot" style="width:24px;height:24px;background:'+bg[i]+';border:none;">'+e[i]+'</div></div>'; } return card('v_mood','<div class="lbl" style="margin-bottom:10px;">Mood this week</div><div class="days">'+h+'</div>'); },
