  v_bp:function(){ return card('v_bp','<div class="barrow"><span class="lbl">Blood pressure</span><span class="lbl">122/79 avg</span></div><svg class="spark" viewBox="0 0 240 54" preserveAspectRatio="none"><polyline points="6,16 50,20 94,14 138,22 182,18 234,20" fill="none" stroke="#1a2e2a" stroke-width="2.2" stroke-linecap="round"/><polyline points="6,40 50,38 94,42 138,36 182,40 234,38" fill="none" stroke="#3aafa9" stroke-width="2.2" stroke-linecap="round"/></svg>'+axis('— Systolic','— Diastolic')); },
