  sch_service:function(){ return card('sch_service','<div class="row"><div class="goalicon" style="background:rgba(58,175,169,.14);"><svg viewBox="0 0 24 24" width="18" height="18" fill="none"><path d="M12 3v18M3 12h18" stroke="#2b7a78" stroke-width="1.5" stroke-linecap="round" opacity="0"/><circle cx="12" cy="8" r="3.2" stroke="#2b7a78" stroke-width="1.5"/><path d="M5.5 19c0-3.3 2.9-5.5 6.5-5.5s6.5 2.2 6.5 5.5" stroke="#2b7a78" stroke-width="1.5" stroke-linecap="round"/></svg></div><div><div class="h-strong" style="font-size:13.5px;">1:1 Nutrition consultation</div><div class="sub" style="margin-top:2px;">45 min with your coach</div></div><span class="pill flat" style="margin-left:auto;">Available</span></div>'); },
