  if(key==='blank'){ on = new Set(); nbName.textContent = 'Custom build'; }
  else { var p = PRESETS[key]; ctx = JSON.parse(JSON.stringify(p.ctx)); on = new Set(p.on); nbName.textContent = p.name; }
