  // Classify an exercise into a movement pattern. Respects an explicit e.movement,
  // otherwise infers from the name, then falls back to the primary muscles.
  deriveMovement(e){
    if(e.movement) return e.movement;
    const n=(e.name||'').toLowerCase();
    const m=(e.muscles||[]).map(x=>x.toLowerCase());
    const has=(...ws)=>ws.some(w=>n.includes(w));
    if(has('jump','hop','bound','clean','snatch','jerk','throw','plyo','sprint','broad')) return 'power';
    if(has('squat','leg press','goblet','hack','wall sit')) return 'squat';
    if(has('deadlift','romanian','rdl','good morning','hip thrust','glute bridge','swing','hinge')) return 'hinge';
    if(has('lunge','split squat','step up','step-up','stepup')) return 'lunge';
    if(has('row','pulldown','pull-up','pullup','pull up','chin','lat pull')) return 'pull';
    if(has('crossover','fly','flye','curl','raise','extension','kickback','calf','shrug','pushdown')) return 'isolation';
    if(has('press','bench','push-up','pushup','push up','dip','push')) return 'push';
    if(has('plank','bird dog','crunch','sit-up','situp','rotation','twist','pallof','dead bug','hollow','russian','core','ab ')) return 'core';
    if(m.includes('core')) return 'core';
    if(m.includes('back')||m.includes('biceps')) return 'pull';
    if(m.includes('chest')) return 'push';
    if(m.includes('quads')||m.includes('glutes')||m.includes('hamstrings')||m.includes('calves')) return 'squat';
    if(m.includes('shoulders')||m.includes('triceps')) return 'isolation';
    return 'other';
  }

